def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    base_exp = np.e
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 1.0
        penalty = 0.0
        adjustment = 1.0
        complexity = 1.0
        mod_factor = 1.0
        for j in range(1, 15):
            if j % 2 == 0:
                complexity *= (1 + 0.02 * j)
            else:
                complexity *= (1 - 0.01 * j)
            if ratio < 0.12 * j:
                score += ((j ** 3) / (1 + np.exp(ratio * j*0.9))) * complexity
            else:
                score += (np.sqrt(j*j + 1) + np.sin(ratio*j*1.3)) * complexity / (j + 3)
            if (cap * j + j*j) % 9 == 0:
                score *= 1.07
            elif (cap - j*j*j) % 11 == 0:
                score *= 0.94
            if j == 7:
                for k in range(1, 7):
                    diff = cap - item*(k**3)
                    if diff > 0:
                        if diff % (k+3) == 0:
                            penalty += np.sqrt(diff)/(k + 5)
                        else:
                            penalty -= np.log1p(abs(diff))*0.9/(k + 4)
                    else:
                        penalty -= abs(diff)**1.5/(k + 6)
            if ratio > 0.9 and j % 3 == 0:
                adjustment *= 1.15 + 0.025 * j
            elif ratio < 0.15 and j % 4 == 0:
                adjustment *= 0.85 - 0.015 * j
            if j % 5 == 1 and cap % (j + 2) == 0:
                penalty += np.cos(j * ratio) * 0.7
            if j % 6 == 0:
                mod_factor *= 1 + 0.03 * np.sin(ratio * j)
        score += penalty * 0.9
        score *= adjustment * mod_factor
        if score < 0:
            priorities[i] = -score * ((np.log1p(cap + item*2) + np.sqrt(cap)) ** 1.2)
        else:
            if cap > item * 5:
                priorities[i] = -score / (np.cbrt(cap) + 2) * (1 + ratio * 1.2)
            else:
                priorities[i] = -score / (cap + 5) * np.exp(-ratio**2.5)
        if ratio > 0.92:
            priorities[i] *= 1.18
        elif ratio < 0.03:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.97
        elif cap % 5 == 0:
            priorities[i] *= 1.03
        if int(cap) % 4 == 0 and ratio < 0.75:
            priorities[i] *= 0.95 + 0.01 * ratio * 100
        else:
            priorities[i] *= 1.05 - 0.02 * ratio * 50
    return priorities
